#!/usr/bin/env node
/**
 * Verify LinkedIn URLs in the database and identify potentially fake ones
 * This script checks which LinkedIn URLs actually exist vs. which were auto-generated
 */
const { Client } = require('@notionhq/client');
const axios = require('axios');
const fs = require('fs');
const path = require('path');
require('dotenv').config();

// Try to load configuration
let config = {};
try {
  config = require('./config');
} catch (e) {
  // Config file doesn't exist, will use environment variables
}

// Get Notion token and database ID
const notionToken = config.NOTION_TOKEN || process.env.NOTION_TOKEN;
const dbId = config.NOTION_DATABASE_ID || process.env.NOTION_DATABASE_ID;

if (!notionToken || !dbId) {
  console.error('Notion token and database ID are required.');
  process.exit(1);
}

// Initialize Notion client
const notion = new Client({ auth: notionToken });

// Parse command line arguments
const args = process.argv.slice(2);
const options = {
  limit: Infinity,
  dryrun: false,
  removeInvalid: false
};

args.forEach(arg => {
  if (arg.startsWith('--limit=')) {
    options.limit = parseInt(arg.split('=')[1], 10);
  } else if (arg === '--dryrun') {
    options.dryrun = true;
  } else if (arg === '--remove-invalid') {
    options.removeInvalid = true;
  }
});

// Get property value from Notion page
function getPropertyValue(page, propertyName) {
  const property = page.properties[propertyName];
  if (!property) return null;
  
  switch (property.type) {
    case 'title':
      return property.title[0]?.plain_text || null;
    case 'url':
      return property.url || null;
    case 'rich_text':
      return property.rich_text[0]?.plain_text || null;
    default:
      return null;
  }
}

// Check if a LinkedIn URL is likely auto-generated
function isLikelyAutoGenerated(url, orgName) {
  if (!url || !url.includes('linkedin.com/company/')) return false;
  
  const match = url.match(/linkedin\.com\/company\/([^\/]+)/);
  if (!match || !match[1]) return false;
  
  const slug = match[1];
  const orgSlug = orgName
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '')
    .replace(/\s+/g, '-');
  
  // If the slug is exactly what our auto-generation would create, it's suspicious
  return slug === orgSlug || slug === orgName.toLowerCase().replace(/[^a-z0-9]/g, '');
}

// Verify if a LinkedIn URL actually exists
async function verifyLinkedInUrl(url) {
  try {
    // LinkedIn blocks direct scraping, but we can check if the URL returns a 200 status
    // In reality, this might not work due to LinkedIn's anti-scraping measures
    // For now, we'll use heuristics to identify auto-generated URLs
    
    // Check URL format
    if (!url || !url.includes('linkedin.com/company/')) {
      return { exists: false, reason: 'Invalid URL format' };
    }
    
    // Extract company slug
    const match = url.match(/linkedin\.com\/company\/([^\/]+)/);
    if (!match || !match[1]) {
      return { exists: false, reason: 'Could not extract company slug' };
    }
    
    const slug = match[1];
    
    // Check for common patterns of auto-generated slugs
    if (slug.length > 50) {
      return { exists: false, reason: 'Slug too long (likely auto-generated)' };
    }
    
    // For now, we'll mark as "needs manual verification"
    return { exists: 'unknown', reason: 'Needs manual verification' };
    
  } catch (error) {
    return { exists: false, reason: error.message };
  }
}

// Main function
async function verifyLinkedInUrls() {
  console.log('🔍 Finding organizations with LinkedIn profiles...');
  
  const pages = [];
  let cursor;
  let count = 0;
  
  do {
    const response = await notion.databases.query({
      database_id: dbId,
      start_cursor: cursor,
      filter: {
        property: 'LinkedIn',
        url: { is_not_empty: true }
      }
    });
    
    pages.push(...response.results);
    cursor = response.has_more ? response.next_cursor : null;
    count += response.results.length;
    console.log(`Fetched ${count} organizations so far...`);
  } while (cursor && count < options.limit);
  
  console.log(`Found ${pages.length} organizations with LinkedIn profiles`);
  
  const results = {
    total: pages.length,
    likelyAutoGenerated: [],
    needsVerification: [],
    removed: 0
  };
  
  // Process each organization
  for (const page of pages.slice(0, options.limit)) {
    const orgName = getPropertyValue(page, 'Name');
    const linkedInUrl = getPropertyValue(page, 'LinkedIn');
    
    if (!linkedInUrl) continue;
    
    // Check if URL is likely auto-generated
    if (isLikelyAutoGenerated(linkedInUrl, orgName)) {
      console.log(`⚠️  ${orgName}: ${linkedInUrl} - LIKELY AUTO-GENERATED`);
      results.likelyAutoGenerated.push({
        name: orgName,
        url: linkedInUrl,
        pageId: page.id
      });
      
      // Remove if requested
      if (options.removeInvalid && !options.dryrun) {
        try {
          await notion.pages.update({
            page_id: page.id,
            properties: {
              LinkedIn: { url: null }
            }
          });
          console.log(`   ✅ Removed from database`);
          results.removed++;
        } catch (error) {
          console.error(`   ❌ Failed to remove: ${error.message}`);
        }
      } else if (options.removeInvalid && options.dryrun) {
        console.log(`   [DRY RUN] Would remove from database`);
      }
    } else {
      // Needs manual verification
      const verification = await verifyLinkedInUrl(linkedInUrl);
      if (verification.exists === 'unknown') {
        results.needsVerification.push({
          name: orgName,
          url: linkedInUrl,
          pageId: page.id,
          reason: verification.reason
        });
      }
    }
  }
  
  // Generate report
  const reportPath = path.join(__dirname, 'reports', `linkedin-verification-${new Date().toISOString().split('T')[0]}.md`);
  const reportContent = `# LinkedIn URL Verification Report

Generated on: ${new Date().toLocaleString()}

## Summary

- Total LinkedIn URLs checked: ${results.total}
- Likely auto-generated: ${results.likelyAutoGenerated.length}
- Needs manual verification: ${results.needsVerification.length}
- Removed from database: ${results.removed}

## Likely Auto-Generated URLs

These LinkedIn URLs appear to be auto-generated and may not exist:

${results.likelyAutoGenerated.map(org => 
  `- **${org.name}**: ${org.url}`
).join('\n')}

## URLs Needing Manual Verification

These URLs could not be automatically verified:

${results.needsVerification.map(org => 
  `- **${org.name}**: ${org.url} (${org.reason})`
).join('\n')}

## Recommendations

1. Manually verify the "Needs Manual Verification" URLs by visiting them
2. For auto-generated URLs, search for the actual LinkedIn company pages
3. Consider implementing a real LinkedIn API integration for accurate results
4. Add manual review step before bulk updating LinkedIn URLs
`;
  
  fs.mkdirSync(path.dirname(reportPath), { recursive: true });
  fs.writeFileSync(reportPath, reportContent);
  console.log(`\n📄 Report written to: ${reportPath}`);
  
  console.log('\n📊 Summary:');
  console.log(`   Total checked: ${results.total}`);
  console.log(`   Likely auto-generated: ${results.likelyAutoGenerated.length}`);
  console.log(`   Needs verification: ${results.needsVerification.length}`);
  console.log(`   Removed: ${results.removed}`);
  
  if (results.likelyAutoGenerated.length > 0 && !options.removeInvalid) {
    console.log('\n💡 To remove likely auto-generated URLs, run with --remove-invalid flag');
  }
}

// Run the verification
verifyLinkedInUrls().catch(console.error);